import { NextRequest, NextResponse } from 'next/server';
import { connectToDatabase } from '@/lib/mongodb';

export async function GET() {
  try {
    const { db } = await connectToDatabase();
    const docs = await db.collection('documents').find().toArray();
    return NextResponse.json(docs);
  } catch (error) {
    return NextResponse.json({ error: String(error) }, { status: 500 });
  }
}

export async function POST(req: NextRequest) {
  try {
    const data = await req.json();
    const { db } = await connectToDatabase();

    const existing = await db.collection('documents').findOne({ student_id: data.student_id, file_type: data.file_type });

    if (existing) {
      await db.collection('documents').updateOne(
        { _id: existing._id },
        { $set: { file_path: data.file_path, verification_status: 'menunggu', rejection_note: null } }
      );
      const doc = await db.collection('documents').findOne({ _id: existing._id });
      return NextResponse.json(doc);
    }

    const last = await db.collection('documents').find().sort({ id: -1 }).limit(1).toArray();
    const lastNum = last.length > 0 ? parseInt(last[0].id.replace('d', ''), 10) : 0;
    const newId = 'd' + String(lastNum + 1).padStart(3, '0');

    const doc = { id: newId, ...data, verification_status: 'menunggu', rejection_note: null };
    await db.collection('documents').insertOne(doc);
    return NextResponse.json(doc);
  } catch (error) {
    return NextResponse.json({ error: String(error) }, { status: 500 });
  }
}

export async function PUT(req: NextRequest) {
  try {
    const data = await req.json();
    const { db } = await connectToDatabase();
    const { id, ...updateData } = data;
    await db.collection('documents').updateOne({ id }, { $set: updateData });

    // Update student status based on docs
    const doc = await db.collection('documents').findOne({ id });
    if (doc) {
      const docs = await db.collection('documents').find({ student_id: doc.student_id }).toArray();
      const allApproved = docs.every((d: any) => d.verification_status === 'disetujui');
      const hasRejected = docs.some((d: any) => d.verification_status === 'ditolak');

      if (allApproved) {
        await db.collection('students').updateOne({ id: doc.student_id }, { $set: { pendaftaran_status: 'terverifikasi' } });
      } else if (hasRejected) {
        await db.collection('students').updateOne({ id: doc.student_id }, { $set: { pendaftaran_status: 'belum_lengkap' } });
      }
    }

    return NextResponse.json({ success: true });
  } catch (error) {
    return NextResponse.json({ error: String(error) }, { status: 500 });
  }
}
